@php
    use Filament\Support\Enums\Alignment;
@endphp

@props([
    'actions' => [],
    'alignment' => Alignment::Start,
    'fullWidth' => false,
])

@php
    if (is_array($actions)) {
        $actions = array_filter(
            $actions,
            fn ($action): bool => $action->isVisible(),
        );
    }

    if (! $alignment instanceof Alignment) {
        $alignment = filled($alignment) ? (Alignment::tryFrom($alignment) ?? $alignment) : null;
    }

    $hasActions = false;

    $hasSlot = ! \Filament\Support\is_slot_empty($slot);
    $actionsAreHtmlable = $actions instanceof \Illuminate\Contracts\Support\Htmlable;

    if ($hasSlot) {
        $hasActions = true;
    } elseif ($actionsAreHtmlable) {
        $hasActions = ! \Filament\Support\is_slot_empty($actions);
    } else {
        $hasActions = filled($actions);
    }
@endphp

@if ($hasActions)
    <div
        {{
            $attributes->class([
                'fi-ac',
                'fi-width-full' => $fullWidth,
                ($alignment instanceof Alignment) ? "fi-align-{$alignment->value}" : (is_string($alignment) ? $alignment : null) => ! $fullWidth,
            ])
        }}
    >
        @if ($hasSlot)
            {{ $slot }}
        @elseif ($actionsAreHtmlable)
            {{ $actions }}
        @else
            @foreach ($actions as $action)
                {{ $action }}
            @endforeach
        @endif
    </div>
@endif

@props([
    'actions' => [],
    'badge' => null,
    'badgeColor' => null,
    'button' => false,
    'buttonGroup' => null,
    'color' => null,
    'dropdownMaxHeight' => null,
    'dropdownOffset' => null,
    'dropdownPlacement' => null,
    'dropdownWidth' => null,
    'group' => null,
    'icon' => null,
    'iconSize' => null,
    'iconButton' => false,
    'label' => null,
    'link' => false,
    'size' => null,
    'tooltip' => null,
    'triggerView' => null,
    'view' => null,
])

@php
    $group ??= \Filament\Actions\ActionGroup::make($actions)
        ->badgeColor($badgeColor)
        ->color($color)
        ->dropdownMaxHeight($dropdownMaxHeight)
        ->dropdownOffset($dropdownOffset)
        ->dropdownPlacement($dropdownPlacement)
        ->dropdownWidth($dropdownWidth)
        ->icon($icon)
        ->iconSize($iconSize)
        ->label($label)
        ->size($size)
        ->tooltip($tooltip)
        ->triggerView($triggerView)
        ->view($view);

    $badge === true
        ? $group->badge()
        : $group->badge($badge);

    if ($button) {
        $group
            ->button()
            ->iconPosition($attributes->get('iconPosition') ?? $attributes->get('icon-position'))
            ->outlined($attributes->get('outlined') ?? false);
    }

    if ($buttonGroup) {
        $group->buttonGroup();
    }

    if ($iconButton) {
        $group->iconButton();
    }

    if ($link) {
        $group->link();
    }
@endphp

{{ $group }}

@php
    use Filament\Support\Enums\Alignment;
    use Filament\Support\Enums\VerticalAlignment;
@endphp

<div>
    <div
        @class([
            'fi-no',
            'fi-align-' . static::$alignment->value,
            'fi-vertical-align-' . static::$verticalAlignment->value,
        ])
        role="status"
    >
        @foreach ($notifications as $notification)
            {{ $notification }}
        @endforeach
    </div>

    @if ($broadcastChannel = $this->getBroadcastChannel())
        @script
            <script>
                window.addEventListener('EchoLoaded', () => {
                    window.Echo.private(@js($broadcastChannel)).notification(
                        (notification) => {
                            setTimeout(
                                () =>
                                    $wire.handleBroadcastNotification(
                                        notification,
                                    ),
                                500,
                            )
                        },
                    )
                })

                if (window.Echo) {
                    window.dispatchEvent(new CustomEvent('EchoLoaded'))
                }
            </script>
        @endscript
    @endif
</div>
